import { React, useEffect, useState } from 'react'
import { Box, Card, CardContent, CardHeader, CircularProgress, Container, Fade, Grid, makeStyles, MenuItem, Typography } from '@material-ui/core'
import SubjectCards from '../components/SubjectCards'
import urslogo from '../images/urslogo.png'
import axios from 'axios'

import Cookies from 'js-cookie'
import { useNavigate } from 'react-router-dom'


const useStyle = makeStyles(theme => {
    return {
        root: {
            display: 'flex'
        }, 
        loading: {
            display: 'flex',
            height: '100%',
            width: '100%',
            zIndex: 1,
            position: 'absolute',
            background: '#f9fbfd',
            top: '-40px'
        },
        loadingImage: {
            width: '200px',
            margin: 'auto'
        }

    }
});



export default function StudentDashboard() {

    const classes = useStyle();

    const navigate = useNavigate();
    const Cookie = Cookies.get('idLoggedIn');
    const [isLoading, setIsLoading] = useState(true);

    const [noClassroom, setNoClassroom] = useState(true);

    function sessionCheck() {
        if (!Cookie) {
            navigate('/');
        }
    }

    const showStudentsInfo = () => {
        axios.post('https://ursacapi.000webhostapp.com/api/getStudents.php', JSON.stringify(Cookie))
            .then((response) => {
                if (response.data) {
                    Cookies.set('userName', response.data[0].firstName + ' ' + response.data[0].lastName)
                    Cookies.set('userFirstName', response.data[0].firstName)
                }

            })
            .catch(error => {
                console.log(error);
            })
    }


    const [subjects, setSubjects] = useState([]);

    const showClassrooms = () => {
        axios.post('https://ursacapi.000webhostapp.com/api/getJoinedClassrooms.php', JSON.stringify(Cookie))
            .then((response) => {
                if (response.data == 0) {
                    setNoClassroom(true);
                } else {
                    setSubjects(response.data)
                    setNoClassroom(false);
                    setIsLoading(false)
                }
            })
            .catch(err => console.log(err))
    }


    useEffect(() => {
        sessionCheck();
        showStudentsInfo();
        showClassrooms();

    }, []);





    return (
        <Box>
            {
                isLoading ?
                    <CircularProgress color='secondary' />

                    :

                    <Box>
                        {
                            noClassroom ?

                                <MenuItem disabled>
                                    You have no classroom yet.
                                </MenuItem>

                                :

                                <Container className={classes.root}>
                                    <Grid container spacing={3}>
                                        {subjects.map(subject => (
                                            <Grid item xs={12} sm={6} lg={3} zeroMinWidth key={subject.classroomID}>
                                                <SubjectCards subject={subject} />
                                            </Grid>
                                        ))}
                                    </Grid>
                                </Container>

                        }
                    </Box>

            }

        </Box>
    )
}
